2978	\begin{lemma}\leanok
2979	[The over-equivalence inverse is a dense subsite]
2980	  \label{lem:overEquivalence_inverse_isDenseSubsite}
2981	  \lean{AlgebraicGeometry.overEquivalence_inverse_isDenseSubsite}
2982	  \uses{lem:overEquivalence_functor_isCocontinuous, lem:overEquivalence_inverse_isCocontinuous}
2983	  \textit{Topological layer of bridge C; the dense-subsite witness assembled from the two
2984	  cocontinuities.}
2985	  The inverse of \(\mathrm{Opens.overEquivalence}\,U\) is a dense subsite for \((J_U, J_X|_U)\).
2986	  This is formal: an equivalence both of whose legs are cocontinuous
2987	  (\cref{lem:overEquivalence_functor_isCocontinuous},
2988	  \cref{lem:overEquivalence_inverse_isCocontinuous}) yields a dense subsite on its inverse.
2989	\end{lemma}
