2992	[The over-equivalence functor is continuous]
2993	  \label{lem:overEquivalence_functor_isContinuous}
2994	  \lean{AlgebraicGeometry.overEquivalence_functor_isContinuous}
2995	  \uses{lem:overEquivalence_inverse_isCocontinuous}
